14: 
15: Http::Code ListenersHandler::handlerDrainListeners(Http::ResponseHeaderMap&,
16:                                                    Buffer::Instance& response,
17:                                                    AdminStream& admin_query) {
18:   const Http::Utility::QueryParamsMulti params = admin_query.queryParams();
19: 
20:   ListenerManager::StopListenersType stop_listeners_type =
21:       params.getFirstValue("inboundonly").has_value()
22:           ? ListenerManager::StopListenersType::InboundOnly
23:           : ListenerManager::StopListenersType::All;
24: 
25:   const bool graceful = params.getFirstValue("graceful").has_value();
26:   const bool skip_exit = params.getFirstValue("skip_exit").has_value();
27:   if (skip_exit && !graceful) {
28:     response.add("skip_exit requires graceful\n");
29:     return Http::Code::BadRequest;
30:   }
31:   if (graceful) {
32:     // Ignore calls to /drain_listeners?graceful if the drain sequence has
33:     // already started.
34:     if (!server_.drainManager().draining()) {
35:       server_.drainManager().startDrainSequence([this, stop_listeners_type, skip_exit]() {
36:         if (!skip_exit) {
37:           server_.listenerManager().stopListeners(stop_listeners_type, {});
38:         }
39:       });
40:     }
41:   } else {
42:     server_.listenerManager().stopListeners(stop_listeners_type, {});
43:   }
44: 
45:   response.add("OK\n");
46:   return Http::Code::OK;
47: }
48: 
49: Http::Code ListenersHandler::handlerListenerInfo(Http::ResponseHeaderMap& response_headers,
50:                                                  Buffer::Instance& response,
51:                                                  AdminStream& admin_query) {
52:   const Http::Utility::QueryParamsMulti query_params = admin_query.queryParams();
53:   const auto format_value = Utility::formatParam(query_params);
54: 
55:   if (format_value.has_value() && format_value.value() == "json") {
56:     writeListenersAsJson(response);
57:     response_headers.setReferenceContentType(Http::Headers::get().ContentTypeValues.Json);
58:   } else {
59:     writeListenersAsText(response);
60:   }
61:   return Http::Code::OK;
62: }
63: 
64: void ListenersHandler::writeListenersAsJson(Buffer::Instance& response) {
65:   envoy::admin::v3::Listeners listeners;
66:   for (const auto& listener : server_.listenerManager().listeners()) {
67:     envoy::admin::v3::ListenerStatus& listener_status = *listeners.add_listener_statuses();
68:     listener_status.set_name(listener.get().name());
69:     Network::Utility::addressToProtobufAddress(
70:         *listener.get().listenSocketFactories()[0]->localAddress(),
71:         *listener_status.mutable_local_address());
72:     for (std::vector<Network::ListenSocketFactoryPtr>::size_type i = 1;
73:          i < listener.get().listenSocketFactories().size(); i++) {
74:       auto address = listener_status.add_additional_local_addresses();
75:       Network::Utility::addressToProtobufAddress(
76:           *listener.get().listenSocketFactories()[i]->localAddress(), *address);
77:     }
78:   }
79:   response.add(MessageUtil::getJsonStringFromMessageOrError(listeners, true)); // pretty-print
80: }
81: 
82: void ListenersHandler::writeListenersAsText(Buffer::Instance& response) {
83:   for (const auto& listener : server_.listenerManager().listeners()) {
84:     for (auto& socket_factory : listener.get().listenSocketFactories()) {
85:       response.add(fmt::format("{}::{}\n", listener.get().name(),
86:                                socket_factory->localAddress()->asString()));
87:     }
88:   }
89: }
90: 
